import SwiftUIimport Combineimport AVFoundationimport Visionclass CameraManager: NSObject, ObservableObject, AVCaptureVideoDataOutputSampleBufferDelegate {        let session = AVCaptureSession()        private let videoOutput = AVCaptureVideoDataOutput()        private let queue = DispatchQueue(label: "camera.queue")        func start() {                session.beginConfiguration()                // Usa la cámara trasera        guard let device = AVCaptureDevice.default(.builtInWideAngleCamera,                                                   for: .video,                                                   position: .back) else {            print("No camera available")            return        }                do {                        // Entrada de cámara            let input = try AVCaptureDeviceInput(device: device)                        if session.canAddInput(input) {                session.addInput(input)            }                    } catch {            print("Camera input error:", error)            return        }                // Output de video        videoOutput.setSampleBufferDelegate(self, queue: queue)        videoOutput.alwaysDiscardsLateVideoFrames = true                if session.canAddOutput(videoOutput) {            session.addOutput(videoOutput)        }                session.commitConfiguration()                session.startRunning()                print("Camera session started")    }        // Recibe frames de la cámara    func captureOutput(_ output: AVCaptureOutput,                       didOutput sampleBuffer: CMSampleBuffer,                       from connection: AVCaptureConnection) {                guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else {            print("No pixel buffer")            return        }                processFrame(pixelBuffer)    }        // Procesa frame con Vision    private func processFrame(_ pixelBuffer: CVPixelBuffer) {                let request = VNDetectRectanglesRequest { request, error in                        if let error = error {                print("Vision error:", error)                return            }                        guard let results = request.results as? [VNRectangleObservation] else {                return            }                        if results.count > 0 {                print("Rectangle detected:", results.count)            }        }                let handler = VNImageRequestHandler(cvPixelBuffer: pixelBuffer,                                            orientation: .up,                                            options: [:])                do {            try handler.perform([request])        } catch {            print("Vision handler error:", error)        }    }}